async function clearOutdatedCacheVersions() {
    caches.keys().then(names => Promise.all(
        names.map(
            it => it !== CACHE_KEY && it.startsWith("fumux-") ? caches.delete(it) : undefined
        )
    ))
}

self.addEventListener("activate", (ev) => {
    ev.waitUntil(Promise.all([
        clients.claim(),
        clearOutdatedCacheVersions()
    ]))
})

